28	/**
29	 * Organization API Key List (Client Component)
30	 *
31	 * Displays the list of organization API keys with interactive controls:
32	 * - Create new API keys
33	 * - Copy API keys to clipboard
34	 * - Revoke active keys
35	 * - Rotate keys (revoke old, create new)
36	 * - Delete keys
37	 *
38	 * Uses useSuspenseQuery to consume server-prefetched data without client-side fetch.
39	 */
40	export function OrgApiKeyList() {
41	  const trpc = useTRPC();
42	  const queryClient = useQueryClient();
43	
44	  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
45	  const [newKeyName, setNewKeyName] = useState("");
46	  const [createdKey, setCreatedKey] = useState<string | null>(null);
47	
48	  // Use prefetched data from server (no client-side fetch)
49	  const { data: apiKeys } = useSuspenseQuery({
50	    ...trpc.orgApiKeys.list.queryOptions(),
51	    refetchOnMount: false,
52	    refetchOnWindowFocus: false,
53	    staleTime: 5 * 60 * 1000, // 5 minutes - API keys rarely change
54	  });
55	
56	  const createMutation = useMutation(
57	    trpc.orgApiKeys.create.mutationOptions({
58	      onSuccess: (data) => {
59	        setCreatedKey(data.key);
60	        setNewKeyName("");
61	        toast.success("Organization API key created successfully");
62	        void queryClient.invalidateQueries({
63	          queryKey: trpc.orgApiKeys.list.queryOptions().queryKey,
64	        });
65	      },
66	      onError: (error) => {
67	        showErrorToast(error, "Failed to create API key");
68	      },
69	    })
70	  );
71	
72	  const revokeMutation = useMutation(
73	    trpc.orgApiKeys.revoke.mutationOptions({
74	      onSuccess: () => {
75	        toast.success("API key revoked successfully");
76	        void queryClient.invalidateQueries({
77	          queryKey: trpc.orgApiKeys.list.queryOptions().queryKey,
78	        });
79	      },
80	      onError: (error) => {
81	        showErrorToast(error, "Failed to revoke API key");
82	      },
83	    })
84	  );
85	
86	  const deleteMutation = useMutation(
87	    trpc.orgApiKeys.delete.mutationOptions({
88	      onSuccess: () => {
89	        toast.success("API key deleted successfully");
90	        void queryClient.invalidateQueries({
91	          queryKey: trpc.orgApiKeys.list.queryOptions().queryKey,
92	        });
93	      },
94	      onError: (error) => {
95	        showErrorToast(error, "Failed to delete API key");
96	      },
97	    })
98	  );
99	
100	  const rotateMutation = useMutation(
101	    trpc.orgApiKeys.rotate.mutationOptions({
102	      onSuccess: (data) => {
103	        setCreatedKey(data.key);
104	        toast.success("API key rotated successfully");
105	        void queryClient.invalidateQueries({
106	          queryKey: trpc.orgApiKeys.list.queryOptions().queryKey,
107	        });
108	      },
109	      onError: (error) => {
110	        showErrorToast(error, "Failed to rotate API key");
111	      },
112	    })
113	  );
114	
115	  const handleCreateKey = () => {
116	    if (!newKeyName.trim()) {
